class _ProxyConnectingAgent(_StandardEndpointFactory):
    _protocol = ProxyAgent._protocol

    def __init__(self, proxyEndpoint, pool=None):
        self._pool = pool
        self.proxyEndpoint = proxyEndpoint

    def request(self, method, uri, headers=None, bodyProducer=None):
        if headers is None:
            headers = Headers()

        if not headers.hasHeader(b'host'):
            headers = headers.copy()
            headers.addRawHeader(
                b'host', self._computeHostValue(None, None, None))

        return _makeGetterFactory(
            uri, _ProxyConnectingAgent,
            self.proxyEndpoint,
            self._protocol,
            self._pool,
            False,
            None,
            self.contextFactory,
            self.bindAddress).request(method, uri, headers, bodyProducer)


