def _get_external_contract_key(
    contract_name: str,
    contract_addr: IRnode,
    context: Context,
) -> str:
    if contract_name == "this":
        if context.is_constant():
            raise StateAccessViolation("May not use 'this' in a constant function", None)
        if contract_addr.location == STORAGE:
            return "storage"
        if contract_addr.location == CALLDATA:
            return "calldata"
        raise CompilerPanic("unreachable")
    return contract_name
def _pack_arguments(
    sig: FunctionSignature,
    args_ir: List[IRnode],
    context: Context,
    for_call: bool = False,
) -> Tuple[IRnode, List[IRnode], int, int]:
    if len(args_ir) != len(sig.args):
        raise StructureException(
            f"Wrong number of arguments for: {sig.name}"
            + f" (given: {len(args_ir)}, expected: {len(sig.args)})",
            args_ir[0].ast_source,
        )
    pack_args = []
    arg_packer = []
    args_ofst = 0
    for i, (arg, arg_ir) in enumerate(zip(sig.args, args_ir)):
        if arg.is_constant:
            if not arg_ir.is_constant:
                raise StateAccessViolation(
                    f"Argument {arg.name} is constant, but was given as mutable",
                    arg.ast_source,
                )
            if for_call:
                arg_ir = IRnode.from_list(arg_ir.value, typ=arg.typ, location=ARGUMENT)
            arg_packer.append(["pass"])
        else:
            if arg_ir.is_constant:
                raise StateAccessViolation(
                    f"Argument {arg.name} is not constant, but was given as constant",
                    arg.ast_source,
                )
            if arg_ir.typ != arg.typ:
                raise TypeMismatch(
                    f"Argument {arg.name} must be of type {arg.typ}, not {arg_ir.typ}",
                    arg.ast_source,
                )
            if arg_ir.location == STORAGE or arg_ir.location == DATA:
                arg_packer.append(["store", arg_ir])
            elif arg_ir.location == MEMORY:
                arg_packer.append(["calldatacopy", arg_ir, args_ofst, arg_ir.typ.size_in_bytes])
            elif arg_ir.location == CALLDATA:
                arg_packer.append(["calldatacopy", arg_ir, args_ofst, arg_ir.typ.size_in_bytes])
            else:
                raise CompilerPanic(f"Unhandled location: {arg_ir.location}")
            args_ofst += arg_ir.typ.size_in_bytes
        pack_args.append(arg_ir)
    return (
        IRnode(0, typ=sig.args[0].typ, location=DATA),
        arg_packer,
        args_ofst,
        args_ofst,
    )
def _unpack_arguments(
    sig: FunctionSignature,
    ret_types: List[old.NodeType],
    ret_packer: List[List[str]],
    context: Context,
) -> List[IRnode]:
    ret_values = []
    for i, ret_type in enumerate(ret_types):
        ret_ir = IRnode(0, typ=ret_type, location=MEMORY)
        ret_ir.mutable = False
        ret_values.append(ret_ir)
        ret_packer[i].append(["pass"])
    return ret_values
def _is_constant(irs: List[IRnode]) -> bool:
    if not irs:
        return True
    return all(ir.is_constant for ir in irs)
def _copy_call(ir: IRnode, args_ofst: int, args_len: int, context: Context) -> IRnode:
    if args_len == 0:
        return IRnode("pass")
    dest = IRnode(0, typ=ir.typ, location=MEMORY)
    copy_arg = IRnode(
        ["calldatacopy", dest, args_ofst, args_len],
        typ=BaseType("num_type"),
        location=ARGUMENT,
    )
    copy_arg.source_pos = getpos(ir.ast_source)
    return copy_arg
def _make_external_call(
    contract_name: str,
    contract_addr: IRnode,
    context: Context,
    args_ir: List[IRnode],
    sig: FunctionSignature,
    value=None,
    gas=None,
    skip_contract_check=None,
    expr=None,
    return_type: Optional[old.NodeType] = None,
) -> IRnode:
    if value is None:
        value = 0
    if gas is None:
        gas = "gas"
    if skip_contract_check is None:
        skip_contract_check = False
    if return_type is None:
        return_type = sig.return_type
    assert len(args_ir) == len(sig.args)
    args_ofst = 0
    if contract_addr.location == CALLDATA:
        args_packer, args_ofst, args_len = _pack_arguments(sig, args_ir, context, for_call=True)
        args_ir = [_copy_call(contract_addr, args_ofst, args_len, context)]
        args_ofst = 0
    args_packer, args_ofst, args_len = _pack_arguments(sig, args_ir, context)
    return IRnode(
        _external_call_helper(
            contract_addr,
            sig,
            args_ir,
            context,
            value,
            gas,
            skip_contract_check,
            contract_addr.ast_source,
        ),
        typ=return_type,
        annotation="external_call",
        location=MEMORY,
    )
