    def _check_session(self):
        """check if a session is valid

        @rtype: boolean
        @return: if the session is valid or not
        """
        if SESSION_KEY in cherrypy.session:
            username = cherrypy.session[SESSION_KEY]
            try:
                self._get_user_dn(username)
                return True
            except ldapcherry.backend.LDAPException, e:
                cherrypy.log.error(
                    msg="session not valid: %(e)s" % {'e': e.message},
                    severity=logging.DEBUG
                )
                return False
        else:
            return False
    def _get_user_dn(self, username):
        """ get the user dn from the username
        """
        if self.auth_mode == 'file':
            if username in self.users:
                return self.users[username]['dn']
