def calculate_type_for_external_return(typ):
    if typ is None:
        return None
    if isinstance(typ, new.ArrayLike):
        return new.ArrayLike(calculate_type_for_external_return(typ.subtype), typ.count)
    if isinstance(typ, new.TupleLike):
        return typ
    if isinstance(typ, new.BaseTypeDefinition):
        return new.BaseTypeDefinition("uint256", typ.unit, typ.positional, typ.is_constant)
    if isinstance(typ, new.DynamicArrayType):
        if typ.subtype is not None:
            return new.DynamicArrayType(typ.subtype, typ.count)
        return new.DynamicArrayType(new.BaseType("uint256"), typ.count)
    if isinstance(typ, new.StructType):
        return new.StructType(
            {
                n: calculate_type_for_external_return(t)
                for (n, t) in typ.members.items()
            },
            typ.is_dynamic_size,
            typ.is_dynamic_offset,
        )
    if isinstance(typ, new.InterfaceType):
        return typ
    if isinstance(typ, new.MappingType):
        return new.MappingType(typ.key_type, typ.value_type)
    if isinstance(typ, new.ContractType):
        return typ
    if isinstance(typ, (new.SignatureDefinition, new.FunctionType)):
        return typ
    raise InvalidType("calculate_type_for_external_return called on non-external type")
