        if arg.name is not None and arg.name != arg.canonical_name:
            arg_packer.append(["mstore", arg_ir, arg.canonical_name])
            arg_ir = arg_ir + 32
        if context.vars.get(arg.name) is not None:
            arg_packer.append(["mstore", arg_ir, context.vars.get(arg.name)])
        else:
            arg_packer.append(["mstore", arg_ir, arg_ir])
        if arg.is_literal:
            arg_packer += [
                ["mstore", arg_ir + 32, arg.value],
                ["mstore", arg_ir + 64, arg.value],
            ]
        if isinstance(arg.typ, (new.StructType, new.InterfaceType)):
            if isinstance(arg.typ, new.StructType):
                arg_t = arg.typ
