                arg_t = context.get_struct(arg.typ.name, None)
            arg_packer += [
                pack_struct(
                    arg_ir + 96,
                    arg_t,
                    arg_t.struct_members(),
                    arg.value,
                    context,
                    arg.name,
                )
            ]
        else:
            arg_ofst = add_ofst(buf, args_ofst)
            arg_packer += [
                make_setter(
                    arg_ofst,
                    arg_ir,
                    location=arg_ir.location,
                    is_immutable=arg.is_immutable,
