def get_topic_sigs(topics: Expr, context: Context) -> Tuple[TupleType, TupleType]:
    if topics is None:
        raise TypeMismatch("Topic not specified", topics)
    if not isinstance(topics, (List, Tuple)):
        raise TypeMismatch("Topics is not a list or tuple", topics)
    if len(topics) > 4:
        raise TypeMismatch(
            "Expecting at most 4 topics", topics,
        )
    for topic in topics:
        if not isinstance(topic, Expr) or topic._location != "memory":
            raise TypeMismatch("Topic is not a memory location", topic)
    if not topics:
        return (TupleType([]), TupleType([]))
    sigs = []
    for topic in topics:
        sigs.append(_get_event_argument_types(topic.typ, context.sigs))
    return sigs[0], sigs[1:]
