def redirect_url(location, login_page_redirect=False):
	redirect_to = (
		login_page_redirect
		and get_safe_redirect()
		or location
	)

	return (
		"/login?redirect-to="
		+ redirect_to.replace(' ', '%20').replace("#", "%23")
		+ "#login"
	)

