def build_user_doc_map():
	'''Build a map of {user: [roles, ...]} from user permissions'''
	user_doc_map = {}

	for user, roles in frappe.db.sql('''
		SELECT
			`tabUser`.name, `tabHas Role`.parent,
			`tabUser`.docstatus, `tabUser`.enabled
		FROM
			`tabUser`, `tabHas Role`
		WHERE
			`tabHas Role`.parent = `tabUser`.name AND
			`tabUser`.enabled = 1
			AND `tabUser`.user_type != 'Website User'
		ORDER BY
			`tabUser`.name ASC''', as_dict=True):
		user_doc_map.setdefault(user, []).append(roles.parent)

	return user_doc_map

def build_user_perm_map():
	'''Build a map of {user: [doctype, ...]} with read access via User Permissions'''
	user_perm_map = {}

	for user, allow in frappe.db.sql('''
		SELECT
			`tabUser`.name, `tabUser Permission`.allow
		FROM
			`tabUser`, `tabUser Permission`
		WHERE
			`tabUser`.name = `tabUser Permission`.user AND
			`tabUser`.enabled = 1
			AND `tabUser`.docstatus < 2
			AND `tabUser`.user_type != 'Website User'
		ORDER BY
			`tabUser`.name ASC''', as_dict=True):
		user_perm_map.setdefault(user, []).append(allow)

	return user_perm_map

